class Solution {
public:
    string getHint(string secret, string guess) {
        int bulls = 0, cows = 0;
        int s[10] = {0}, g[10] = {0};
        for (int i = 0; i < secret.size(); i++) {
            if (secret[i] == guess[i]) {
                bulls++;
            } else {
                s[secret[i] - '0']++;
                g[guess[i] - '0']++;
            }
        }
        for (int i = 0; i < 10; i++) {
            cows += min(s[i], g[i]);
        }
        return to_string(bulls) + "A" + to_string(cows - bulls) + "B";
    }
};
```
